schema.blog_post_tags:
CREATE TABLE IF NOT EXISTS "blog_post_tags" (
  "id" INTEGER DEFAULT nextval('blog_post_tags_id_seq'::regclass) NOT NULL,
  "post_id" INTEGER NOT NULL,
  "tag_id" INTEGER NOT NULL
);

schema.conversations:
CREATE TABLE IF NOT EXISTS "conversations" (
  "id" INTEGER DEFAULT nextval('conversations_id_seq'::regclass) NOT NULL,
  "title" TEXT NOT NULL,
  "created_at" TIMESTAMP WITHOUT TIME ZONE DEFAULT CURRENT_TIMESTAMP NOT NULL
);

schema.registrations:
CREATE TABLE IF NOT EXISTS "registrations" (
  "id" INTEGER DEFAULT nextval('registrations_id_seq'::regclass) NOT NULL,
  "user_id" CHARACTER VARYING NOT NULL,
  "exam_id" INTEGER NOT NULL,
  "registered_at" TIMESTAMP WITHOUT TIME ZONE DEFAULT now()
);

schema.sessions:
CREATE TABLE IF NOT EXISTS "sessions" (
  "sid" CHARACTER VARYING NOT NULL,
  "sess" JSONB NOT NULL,
  "expire" TIMESTAMP WITHOUT TIME ZONE NOT NULL
);
